// THE NEWMRR MISSION ENGINE
// 16 tracks × 12 weeks = 192 unique weekly missions
// Driven by: phase (grind/growth/gold) + biggest block

export interface Mission {
  week: number
  title: string
  why: string
  action: string
  script: string
  whenItWorks: string
  whenItDoesnt: string
  newmrrPrinciple: string
  metric: string
}

export interface MissionTrack {
  phase: string
  block: string
  trackName: string
  missions: Mission[]
}

type Phase = 'foundation' | 'momentum' | 'scale'
type Block = 'packaging' | 'customers' | 'scaling' | 'recurring'

function getBlock(blockAnswer: string): Block {
  if (blockAnswer.includes('package') || blockAnswer.includes('sell') || blockAnswer.includes('what to sell')) return 'packaging'
  if (blockAnswer.includes('customer') || blockAnswer.includes('lead')) return 'customers'
  if (blockAnswer.includes('scale') || blockAnswer.includes('time')) return 'scaling'
  if (blockAnswer.includes('recurring')) return 'recurring'
  return 'customers'
}

