export function getMission(
  phase: Phase,
  block: string,
  weekNumber: number
): Mission | null {
  const blockKey = getBlock(block)
  const track = MISSION_TRACKS[phase]?.[blockKey]
  if (!track) return null
  const weekIndex = ((weekNumber - 1) % 12)
  return track[weekIndex] || null
}

export function getMissionTrackInfo(phase: Phase, block: string): { phase: string; block: string; trackName: string } {
  const blockKey = getBlock(block)
  const phaseLabels: Record<Phase, string> = {
    foundation: 'The Foundation',
    momentum: 'The Momentum',
    scale: 'The Scale',
  }
  const blockLabels: Record<Block, string> = {
    packaging: 'Packaging & Positioning',
    customers: 'Finding Customers',
    scaling: 'Scaling Your Time',
    recurring: 'Building Recurring Revenue',
  }
  return {
    phase: phaseLabels[phase],
    block: blockLabels[blockKey],
    trackName: `${phaseLabels[phase]} — ${blockLabels[blockKey]}`,
  }
}
